"use client";
import { useState, useEffect } from "react";
import { Menu, X } from "lucide-react";

export default function Navbar() {
  const [menuOpen, setMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 50);
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  return (
    <>
      <nav className={`fixed top-0 left-0 right-0 z-50 transition-all duration-500 ${scrolled ? "bg-[#F7F0E6]/90 backdrop-blur-md border-b border-[#C4522A]/10" : ""}`}>
        <div className="flex items-center justify-between px-6 md:px-12 py-5">
          <a href="#" className="font-heading font-800 text-xl tracking-tight text-[#1C1A15]">
            <span className="text-[#C4522A]">SHIKHAR</span>
            <span className="text-xs ml-1 opacity-50 font-normal">MEDIA</span>
          </a>
          <div className="hidden md:flex items-center gap-10 font-heading text-sm font-600 tracking-widest uppercase text-[#1C1A15]/70">
            <a href="#services" className="hover:text-[#C4522A] transition-colors">Services</a>
            <a href="#work" className="hover:text-[#C4522A] transition-colors">Work</a>
            <a href="#niche" className="hover:text-[#C4522A] transition-colors">Our Niche</a>
            <a href="#about" className="hover:text-[#C4522A] transition-colors">About</a>
          </div>
          <a href="#contact" className="hidden md:block bg-[#C4522A] text-white font-heading text-xs font-700 uppercase tracking-widest px-5 py-2.5 hover:bg-[#1C1A15] transition-colors duration-300">
            Let's Talk
          </a>
          <button onClick={() => setMenuOpen(true)} className="md:hidden p-2 text-[#1C1A15]">
            <Menu size={22} />
          </button>
        </div>
      </nav>

      {/* Mobile Menu */}
      {menuOpen && (
        <div className="fixed inset-0 z-[100] bg-[#C4522A] flex flex-col">
          <div className="flex justify-between items-center px-6 py-5">
            <span className="font-heading font-800 text-xl text-white">SHIKHAR</span>
            <button onClick={() => setMenuOpen(false)} className="text-white"><X size={24} /></button>
          </div>
          <div className="flex-1 flex flex-col justify-center px-8 gap-8">
            {["Services", "Work", "Our Niche", "About", "Contact"].map((item) => (
              <a
                key={item}
                href={`#${item.toLowerCase().replace(" ", "")}`}
                onClick={() => setMenuOpen(false)}
                className="font-display text-4xl text-white hover:text-[#1C1A15] transition-colors"
              >
                {item}
              </a>
            ))}
          </div>
          <div className="px-8 py-8 text-white/60 text-sm font-heading">© 2026 Shikhar Media</div>
        </div>
      )}
    </>
  );
}
